(window.webpackJsonp=window.webpackJsonp||[]).push([[242],{869:function(n,t){n.exports='\x3c!-- \ntitle: 11-Git与hub\nsort: \n--\x3e \n\n## 🚛Gitee\n\n> 免费的国内代码托管机构\n>\n> 除了👉速度快\n>\n> 目前还没发现其他的优势\n\n- Branch\n\n  > 分支管理\n\n- Issues\n\n  > 问题反馈与解决\n\n- PullRequests\n\n  > 参与贡献代码\n\n- Wiki\n\n  > 说明文档\n\n## 🚄GitHub\n\n> 全球最大的代码托管机构\n\n## 🦼Git\n\n```bash\ngit config --global user.name fzf\ngit config --global user.email nmdfzf404@163.com\n\n# 最基础的三个命令\ngit init\necho "Hello Git~" > hi.txt\ngit add hi.txt\n# git add .\n# git add -A\ngit commit -a -m "🛵Update hi~"\n\n# 连接到远程仓库\ngit remote add origin https://example.com/demo.git\ngit push\n\n# clone\ngit clone https://example.com/demo.git\ngit pull\n\n# 状态命令\ngit status\ngit log\n\n# 分支\ngit checkout -b newB\ngit checkout master\ngit branch -d newB\n\n# 撤回更改\ngit checkout .\ngit reset HEAD^ -- hi.txt\ngit reset --hard hi.txt\n\n.gitignore\n```\n\n## VSC & GithubDesktop\n\n> 造福初学者\n\n## SSH\n\n> 何为SSH？\n\n```bash\nssh-keygen\n# 添加密钥\ngit remote rm origin\ngit remote add origin git@github.com:xxx/xx.git\n```\n\n## 笔记'}}]);